#!/usr/bin/env node

import { readFile, writeFile } from 'node:fs/promises';
import { dirname, join, resolve } from 'node:path';
import { fileURLToPath } from 'node:url';
import { build } from 'esbuild';

const scriptDirectory = dirname(fileURLToPath(import.meta.url));
const daemonRoot = resolve(scriptDirectory, '..');
const repositoryRoot = resolve(daemonRoot, '../..');
const outputPath = join(repositoryRoot, 'apps/mobile/src/services/termuxDaemonSource.ts');
const checkOnly = process.argv.includes('--check');

const result = await build({
  absWorkingDir: repositoryRoot,
  entryPoints: [join(daemonRoot, 'src/index.ts')],
  bundle: true,
  write: false,
  platform: 'node',
  format: 'esm',
  target: 'node22',
  external: ['ws'],
  alias: {
    '@aicliui/shared': join(repositoryRoot, 'packages/shared/src/index.ts'),
  },
  logLevel: 'silent',
});

const bundledSource = result.outputFiles[0]?.text;
if (!bundledSource) {
  throw new Error('esbuild did not produce the mobile daemon bundle');
}
if (bundledSource.split(/\r?\n/).includes('AICLIUI_DAEMON_SOURCE')) {
  throw new Error('The daemon bundle conflicts with the Termux heredoc delimiter');
}

const generatedSource = [
  '// Generated by packages/daemon/scripts/build-mobile-bundle.mjs. Do not edit.',
  `export const TERMUX_DAEMON_SOURCE = ${JSON.stringify(bundledSource)};`,
  '',
].join('\n');

if (checkOnly) {
  const currentSource = await readFile(outputPath, 'utf8').catch(() => '');
  if (currentSource !== generatedSource) {
    console.error('The Android daemon bundle is stale. Run: npm --workspace @aicliui/daemon run build:mobile-bundle');
    process.exitCode = 1;
  }
} else {
  await writeFile(outputPath, generatedSource, 'utf8');
  console.log(`Updated ${outputPath}`);
}
